import { useState } from "react";

const initialState = { name: "", email: "", message: "" };

export default function Contact() {
  const [form, setForm] = useState(initialState);
  const [errors, setErrors] = useState({});
  const [status, setStatus] = useState({ loading: false, sent: false });

  const handleChange = (event) => {
    const { name, value } = event.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const validate = () => {
    const nextErrors = {};
    if (!form.name.trim()) nextErrors.name = "Name is required.";
    if (!form.email.trim()) {
      nextErrors.email = "Email is required.";
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) {
      nextErrors.email = "Enter a valid email address.";
    }
    if (!form.message.trim()) nextErrors.message = "Message is required.";
    return nextErrors;
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    const nextErrors = validate();
    setErrors(nextErrors);
    if (Object.keys(nextErrors).length > 0) return;

    setStatus({ loading: true, sent: false });
    setTimeout(() => {
      setStatus({ loading: false, sent: true });
      setForm(initialState);
    }, 900);
  };

  return (
    <section id="contact" className="contact-section section scroll-reveal">
      <div className="container text-center">
        <span className="section-kicker">Get In Touch</span>
        <h2 className="section-title gradient-title">Contact Me</h2>
        <p className="section-text mx-auto">
          Let&apos;s connect and discuss opportunities, collaborations, or your
          next big idea.
        </p>
      </div>

      <div className="container contact-grid">
        <div className="row g-4 align-items-stretch">
          <div className="col-lg-5">
            <div className="contact-card">
              <h3>Contact Info</h3>
              <p className="contact-text">
                Feel free to reach out anytime. I&apos;m always open to new
                projects and collaborations.
              </p>

              <div className="contact-info">
                <div className="contact-item">
                  <span className="contact-icon">
                    <i className="bi bi-envelope-fill" />
                  </span>
                  <div>
                    <p>Email</p>
                    <a
                      href="mailto:myemail@example.com?subject=Portfolio%20Inquiry&body=Hello%20Gulshan%2C%20I%20want%20to%20connect%20with%20you."
                    >
                      myemail@example.com
                    </a>
                  </div>
                </div>

                <div className="contact-item">
                  <span className="contact-icon">
                    <i className="bi bi-telephone-fill" />
                  </span>
                  <div>
                    <p>Phone</p>
                    <span>+91-00000-00000</span>
                  </div>
                </div>

                <div className="contact-item">
                  <span className="contact-icon">
                    <i className="bi bi-geo-alt-fill" />
                  </span>
                  <div>
                    <p>Location</p>
                    <span>India</span>
                  </div>
                </div>
              </div>

              <div className="contact-socials">
                <a
                  href="https://www.linkedin.com/"
                  target="_blank"
                  rel="noreferrer"
                >
                  <i className="bi bi-linkedin" />
                </a>
                <a
                  href="https://github.com/"
                  target="_blank"
                  rel="noreferrer"
                >
                  <i className="bi bi-github" />
                </a>
              </div>
            </div>
          </div>

          <div className="col-lg-7">
            <form className="contact-form" onSubmit={handleSubmit}>
              <div className="form-group">
                <label htmlFor="name">Name</label>
                <div className="input-icon">
                  <i className="bi bi-person-fill" />
                  <input
                    type="text"
                    id="name"
                    name="name"
                    value={form.name}
                    onChange={handleChange}
                    placeholder="Your name"
                  />
                </div>
                {errors.name && <span className="form-error">{errors.name}</span>}
              </div>

              <div className="form-group">
                <label htmlFor="email">Email</label>
                <div className="input-icon">
                  <i className="bi bi-envelope" />
                  <input
                    type="email"
                    id="email"
                    name="email"
                    value={form.email}
                    onChange={handleChange}
                    placeholder="you@email.com"
                  />
                </div>
                {errors.email && (
                  <span className="form-error">{errors.email}</span>
                )}
              </div>

              <div className="form-group">
                <label htmlFor="message">Message</label>
                <div className="input-icon textarea">
                  <i className="bi bi-chat-left-text" />
                  <textarea
                    id="message"
                    name="message"
                    rows="5"
                    value={form.message}
                    onChange={handleChange}
                    placeholder="Tell me about your project..."
                  />
                </div>
                {errors.message && (
                  <span className="form-error">{errors.message}</span>
                )}
              </div>

              <button className="btn-primary-cta submit-btn" type="submit" disabled={status.loading}>
                {status.loading ? "Sending..." : "Send Message"}
              </button>

              {status.sent && (
                <div className="form-success">Message sent successfully!</div>
              )}
            </form>
          </div>
        </div>
      </div>
    </section>
  );
}
